var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"음? 베로니카 양 아닌가?","JPN":"うむ？　ベロニカじゃないか。","ENG":"Hmm? Veronica?","TWN":"嗯？貝洛妮卡？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님?","JPN":"ご主人様？","ENG":"Master?","TWN":"主人？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"제가 여기 있는지...... 어떻게 아셨나요?","JPN":"私がここにいると……どうしてわかったんですか？","ENG":"How did you know I was here?","TWN":"您怎麼知道……我在這裡？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하하. 이 공원은 내가 자주 산책을 다니는 곳이거든.","JPN":"ハハハ、この公園は普段よく散歩に来る場所でな。","ENG":"Hah hah. I often come to this park for a walk.","TWN":"哈哈，我經常在這個公園散步。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"이런 곳에서 자넬 만날 줄은 몰랐어.","JPN":"この場所で君に会うとは思わなかった。","ENG":"I didn't think I'd meet you here of all places.","TWN":"沒想到會在這裡碰到你。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그러고 보니 오늘이 마지막 계약일이군. 괜찮으면 같이 잠깐 걷겠나?","JPN":"そういえば今日は契約の最終日だな。よかったら少し歩かないか？","ENG":"Come to think of it, today's the last day of your contract with us. Why don't you walk with me for a few minutes?","TWN":"對了，合約今天到期了吧，要不要陪我走一走？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......네. 모시겠습니다.","JPN":"……はい。お付き添いいたします。","ENG":"...As you wish, Master.","TWN":"……好的。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"이윤정 조교에게 얘기는 들었네. 하필 휴가 중에 부상을 입고 입원했다더군.","JPN":"ユコ君から話は聞いた。せっかくの休暇中に負傷を負って入院していたらしいな。","ENG":"Yoonjung told me that you were injured and hospitalized during your vacation.","TWN":"我聽李芸京助教說，你在休假的時候受傷住院了。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"제 몸보다는...... 모네가 걱정입니다.","JPN":"自分のことより……モネが心配です。","ENG":"I'm more worried about Mone.","TWN":"我沒事……我比較擔心莫妮。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그래. 샤오린 양에게 얘기를 듣고 바로 실종 신고를 했지.","JPN":"だな。シャオリンから話を聞いて、すぐに捜索願は出しておいた。","ENG":"I know. I filed a missing person report right away when Xiao Lin told me.","TWN":"嗯，曉琳告訴我之後馬上報了案。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"뭔가 단서가 나왔나요?","JPN":"何か手がかりはありましたか？","ENG":"Have they found any leads yet?","TWN":"有沒有查出什麼線索？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"흐음. 아직은 행방이 묘연하다네.","JPN":"それがな、まだ行方不明のままだ。","ENG":"Hmm... I'm afraid we don't know much yet.","TWN":"唔，目前還沒有她的下落。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"직원들도 돕고는 있네만, 보다시피 이 도시에는 거친 용병들이 많아서 말이야.","JPN":"他の社員も協力しているが、知ってのとおりこの都市には少々尖った性格の傭兵が多くてな。","ENG":"Our staff is trying to help as well, but as you know, there are many unsavory mercenaries in this city.","TWN":"員工們也在幫忙找，不過你也知道，這個城市裡有很多蠻橫的傭兵。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"일반인 실종 같은 <color=#ffd34c>사소한</color> 일로 자기네 구역에서 소란 피우지 말라고 항의하는 친구들 때문에 조금 곤란한 상황이지.","JPN":"一般人が一人消えたくらいの<color=#ffd34c>些細な</color>問題で自分たちの縄張りで騒がないでほしいと物申す連中が多くて、ちょっと困っている状況さ。","ENG":"It's been a bit tricky with some folks complaining that we shouldn't raise a fuss in their sectors over <color=#ffd34c>\\"trivial\\"</color> matters like missing children.","TWN":"他們對於普通人失蹤這種<color=#ffd34c>小事</color> 而去擾亂他們的區域很是排斥。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님께선 일개 메이드에 불과한 제게 큰 친절을 베풀어 주셨는데......","JPN":"ご主人様は一介のメイドにすぎない私にあれほど親切にしてくださったのに……","ENG":"You've been so kind to me, a mere maid...","TWN":"主人，我不過就是一個女僕，您卻一直很是關照我……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"마지막까지도 폐를 끼치고 마는군요.","JPN":"最後に迷惑ばかりかけてしまいましたね。","ENG":"Yet I've been nothing but a burden for you right up to the end.","TWN":"而我總是在給您添麻煩。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"전혀 그렇지 않네.","JPN":"いや、そんなこと言わないでくれ。","ENG":"Not at all.","TWN":"不要這麼說。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"며칠뿐이라고는 해도 어쨌든 우리 회사의 직원이 아닌가?","JPN":"数日だけとはいえ、君は我が社の社員じゃないか。","ENG":"You've been with us for only a few days, but you're still our employee.","TWN":"雖然我們認識不過幾天，可你也是我們公司的員工啊？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"사장이 곤경에 빠진 직원을 돕는 건 당연한 일이야. 마음에 둘 필요 없네.","JPN":"社長が困っている社員を助けるのは当たり前のことだ。気に留めることではない。","ENG":"Any decent boss would do anything to help one of his employees in need. There's no need to feel guilty about it.","TWN":"作為老闆，當然應該幫助陷入困境的員工，你不必在意。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그래서, 이제 어디로 갈 생각인가?","JPN":"それで、これからどうするつもりかね？","ENG":"So, where are you headed next?","TWN":"那，你想好去哪裡了嗎？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"산책을 가려 합니다.","JPN":"散歩に行こうと思います。","ENG":"I'm thinking of going on a walk.","TWN":"我要去旅行。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"멀리 나가게 될 것 같아...... 미리 인사드리겠습니다.","JPN":"遠出になりそうで……先にここで挨拶申し上げます。","ENG":"And I think I'll be going on quite a long one... so I'll bid you farewell beforehand.","TWN":"可能會去很遠的地方……所以想提前跟您道別。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그래. 다녀오게나.","JPN":"そうか。いってらっしゃい。","ENG":"Very well. See you afterwards.","TWN":"好，你早去早回吧。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......네?","JPN":"……はい？","ENG":"Pardon?","TWN":"……啊？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"떠날 수 있다면 다시 돌아올 수도 있다는 뜻이겠지.","JPN":"さよならとは言わない。去ることもあれば、いつか戻ってくることもあるだろう。","ENG":"If you can leave, that means you can also come back.","TWN":"既然能離開，就說明總是能回來的。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"변변치 않지만 우리 회사의 문은 자네에게 언제나 열려 있다네.","JPN":"立派とは言えたものではないが、我が社の扉はいつまでも君の帰りを待っている。","ENG":"It may not be much, but our company's doors are always open wide for you.","TWN":"雖然我們只是普通公司，但公司的大門永遠為你敞開。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"전 여기 남으라는 주인님의 요청을 거부하고 떠나겠다고 말씀드린 겁니다.","JPN":"私はここに残ってほしいというご主人様の要請を拒んで、去ると申し上げたつもりですが。","ENG":"What I meant was that I'll be declining your offer to stay, that I'll be leaving you.","TWN":"我現在可是拒絕了您讓我留下來的要求。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"메이드인 주제에 감히 명령을 거부한 제게...... 돌아오라고 해 주시는 건가요?","JPN":"メイドの分際で命令を拒否した私に……また戻ってきても良いとおっしゃるのですか？","ENG":"I've dared to disobey you as your maid... yet you invite me to return?","TWN":"作為女僕，我拒絕了主人的命令……即使這樣，您也讓我回來嗎？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"물론일세.","JPN":"もちろんだ。","ENG":"Of course.","TWN":"當然。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"사람에겐 누구나 자신의 길이 있지.","JPN":"人にはみんなそれぞれの道がある。","ENG":"Everyone's got their own path to take.","TWN":"每個人都有自己要走的路。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"때로는 그 길이 서로 어긋나기도 하지만, 계속 걷다 보면 다시 만나게 될 수도 있다네.","JPN":"時には互いに行違うこともあるが、歩き続ければいつかまた会えるかもしれない。","ENG":"Sometimes we go separate ways; but if we keep walking, the path may lead us to meet again.","TWN":"雖然有時會錯開，但走著走著遲早會有再次相見的一天。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그렇게 돌아왔을 때, 환영해 주는 것이야말로 주인......","JPN":"そして帰ってきた時は、歓迎してあげるのが主……","ENG":"And when the time comes, welcoming you with open arms is what any good master...","TWN":"再次相見的時候，發自內心的迎接對方才是主人……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아니, 친구로서 당연한 일이 아니겠나?","JPN":"いや、友人として当たり前のことだと思わないか？","ENG":"... or rather, a friend would do.","TWN":"哦不，朋友之間該做的事不是嗎？"},"stage":{"bg":"SS_ADMIN_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님은, 제가 알던 주인과는 정말 많은 부분에서 다르시군요.","JPN":"ご主人様は、私が知っていたご主人様と本当に色々な面で異なりますね。","ENG":"You're very different from the Master I once served.","TWN":"主人，您跟我所認識的主人真的很不一樣。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"제게 그럴 자격이 있는지는 모르겠지만, 만에 하나......","JPN":"私にその資格があるかどうかはわかりませんが、もし……","ENG":"I don't think I am worthy, but if...","TWN":"我不知道我有沒有那個資格，但是如果……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"정말, 만에 하나라도 기회가 주어진다면.","JPN":"もし万が一、一度でもチャンスがあるのなら……","ENG":"If I get the opportunity again somehow...","TWN":"如果有那個機會，"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"꼭 돌아와서 다시 한 번 주인님을 모시고 싶습니다.","JPN":"必ず戻ってきて、もう一度ご主人様に仕えたいと思います。","ENG":"I wish to return and serve you once again.","TWN":"我一定會回來重新為您服務。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그럼 이만. 부디 평안하시길.","JPN":"それでは、失礼いたします。どうかご自愛ください。","ENG":"Farewell, then. I bid you peace and prosperity...","TWN":"那我走了，願您一切安康。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......주인님.","JPN":"……ご主人様。","ENG":"Master.","TWN":"……主人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};